const command = msg.command || {};
const authUser = msg.payload && typeof msg.payload === 'object' && !Array.isArray(msg.payload)
  ? JSON.parse(JSON.stringify(msg.payload))
  : null;
const kioskPayload = command.kiosk && typeof command.kiosk === 'object' ? command.kiosk : {};
const wifiPayload = command.wifi && typeof command.wifi === 'object' ? command.wifi : (kioskPayload.wifi || {});
const stationid = String(command.stationid || kioskPayload.stationid || '').trim();
const ssid = String(command.ssid || wifiPayload.ssid || wifiPayload.name || '').trim();
const password = String(command.password ?? wifiPayload.password ?? '').trim();
const now = Date.now();
const requestId = String(command.requestId || `wifi-change-${stationid || 'unknown'}-${now}`).trim();

function response(status, statusEn, extra = {}) {
  return {
    _session: msg._session,
    payload: {
      action: 'wifichange',
      stationid,
      kiosk: stationid,
      status,
      statuscode: status,
      status_en: statusEn,
      requestId,
      timerequested: Number(command.timerequested || now),
      timeresponded: Date.now(),
      ...extra
    }
  };
}

if (!stationid) {
  return [null, response(0, 'Missing stationid for V2 Wi-Fi command')];
}

if (!ssid) {
  return [null, response(0, 'Wi-Fi name is required')];
}

msg._v2Wifi = {
  authUser,
  command: { ...command, requestId, ssid, password },
  stationid,
  requestId,
  timerequested: Number(command.timerequested || now),
  ssid,
  password
};
msg.payload = {
  path: 'kiosks',
  query: [{ fieldPath: 'stationid', opStr: '==', value: stationid }]
};
return [msg, null];

const V2_TYPES = new Set(['CT3', 'CT4', 'CT8', 'CT12', 'CK48']);
const docs = Array.isArray(msg.payload) ? msg.payload : [];
const ctx = msg._v2Wifi || {};
const command = ctx.command || msg.command || {};
const authUser = ctx.authUser || null;
const stationid = String(ctx.stationid || command.stationid || '').trim();
const ssid = String(ctx.ssid || command.ssid || '').trim();
const password = String(ctx.password ?? command.password ?? '').trim();
const requestId = String(ctx.requestId || command.requestId || `wifi-change-${stationid}-${Date.now()}`).trim();
const timerequested = Number(ctx.timerequested || command.timerequested || Date.now());
const sessionValue = msg._session || command.admin || null;
const stationidUpper = stationid.toUpperCase();

function buildResponse(status, statusEn, extra = {}) {
  return {
    _session: sessionValue,
    payload: {
      action: 'wifichange',
      stationid,
      kiosk: stationid,
      status,
      statuscode: status,
      status_en: statusEn,
      requestId,
      timerequested,
      timeresponded: Date.now(),
      ...extra
    }
  };
}

function toModules(kiosk) {
  if (Array.isArray(kiosk?.modules)) return kiosk.modules;
  if (kiosk?.modules && typeof kiosk.modules === 'object') return Object.values(kiosk.modules);
  return [];
}

function getModuleIds(kiosk) {
  const seen = new Set();
  return toModules(kiosk)
    .filter((module) => module?.output !== false)
    .map((module) => String(module?.id || '').trim())
    .filter((moduleid) => {
      if (!moduleid || seen.has(moduleid)) return false;
      seen.add(moduleid);
      return true;
    });
}

if (!authUser) {
  return [null, buildResponse(0, 'V2 Wi-Fi command requires authenticated dashboard context'), null];
}

const isAdmin = authUser.role === 'admin' || authUser.username === 'chargerent';
if (!isAdmin && authUser.commands?.['client edit'] !== true) {
  return [null, buildResponse(0, 'Permission denied'), null];
}

if (docs.length === 0) {
  return [null, buildResponse(0, `Kiosk ${stationid} not found`), null];
}

const kiosk = docs[0] || {};
const hardwareType = String(kiosk?.hardware?.type || '').toUpperCase();
const modules = toModules(kiosk);
const moduleids = getModuleIds(kiosk);
const isV2 = kiosk?.isNewSchema === true ||
  V2_TYPES.has(hardwareType) ||
  modules.some((module) => Array.isArray(module?.slots)) ||
  /^(CA|FR|US)8\d{3}$/.test(stationidUpper) ||
  /^(CAB|FRB|USB)\d{4}$/.test(stationidUpper);

if (!isV2) {
  return [null, buildResponse(0, `${stationid} is not a V2 kiosk`), null];
}

if (!ssid) {
  return [null, buildResponse(0, 'Wi-Fi name is required'), null];
}

if (moduleids.length === 0) {
  return [null, buildResponse(0, `No modules found for ${stationid}`), null];
}

const nextWifi = { name: ssid, password };
const publishMessages = moduleids.map((moduleid) => ({
  topic: `/${stationid}/${moduleid}/user/get`,
  payload: {
    cmd: 'setWifi',
    username: ssid,
    password
  },
  qos: '0',
  retain: 'false'
}));

const nextKiosk = {
  ...kiosk,
  wifi: nextWifi
};
if (typeof command.kiosk?.status === 'string' && command.kiosk.status.trim()) {
  nextKiosk.status = command.kiosk.status.trim();
}

const responseMessage = buildResponse(
  1,
  `Wi-Fi update sent to ${stationid} (${moduleids.length} modules)`,
  { kiosk: nextKiosk, wifi: { name: ssid }, moduleids, moduleCount: moduleids.length }
);
const provisionid = String(kiosk?.provisionid || '').trim();
const firestoreContent = {
  wifi: nextWifi,
  updatedAt: new Date().toISOString()
};
if (typeof nextKiosk.status === 'string' && nextKiosk.status.trim()) {
  firestoreContent.status = nextKiosk.status.trim();
}
const firestoreMessage = provisionid
  ? {
      payload: {
        path: `kiosks/${provisionid}`,
        content: firestoreContent
      }
    }
  : null;

node.warn(`Dashboard set Wi-Fi for ${stationid} modules [${moduleids.join(', ')}] request ${requestId}`);
return [publishMessages, responseMessage, firestoreMessage];
